{
  "openapi": "3.1.0",
  "info": {
    "title": "GitHub Issues & Comments API (subset + search)",
    "description": "Subset of GitHub REST API for issue/PR search, issue comment listing / retrieval, listing repository labels, and issue assignment.",
    "version": "1.4.0"
  },
  "servers": [
    {
      "url": "https://api.github.com",
      "description": "GitHub REST API base"
    }
  ],
  "paths": {
    "/graphql": {
      "post": {
        "operationId": "githubGraphQL",
        "summary": "GitHub GraphQL API",
        "description": "Execute GraphQL queries and mutations against GitHub. Required for Projects v2 custom fields and field values.",
        "requestBody": {
          "required": true,
          "content": {
            "application/json": {
              "schema": { "$ref": "#/components/schemas/GraphQLRequest" },
              "examples": {
                "listProjectV2Fields": {
                  "summary": "List project custom fields (and single-select/iteration options)",
                  "value": {
                    "query": "query($projectId: ID!, $first: Int!, $after: String){ node(id: $projectId){ ... on ProjectV2 { fields(first: $first, after: $after){ pageInfo{ hasNextPage endCursor } nodes{ __typename ... on ProjectV2Field { id name } ... on ProjectV2IterationField { id name configuration { iterations { id startDate }}} ... on ProjectV2SingleSelectField { id name options { id name }}}}}}}",
                    "variables": { "projectId": "PROJECT_ID", "first": 50, "after": null }
                  }
                },
                "listProjectV2ItemFieldValues": {
                  "summary": "List items and their field values (text/date/single-select shown)",
                  "value": {
                    "query": "query($projectId: ID!, $itemsFirst: Int!, $itemsAfter: String, $fieldValuesFirst: Int!){ node(id: $projectId){ ... on ProjectV2 { items(first: $itemsFirst, after: $itemsAfter){ pageInfo{ hasNextPage endCursor } nodes{ id fieldValues(first: $fieldValuesFirst){ nodes{ __typename ... on ProjectV2ItemFieldTextValue { text field { ... on ProjectV2FieldCommon { name } } } ... on ProjectV2ItemFieldDateValue { date field { ... on ProjectV2FieldCommon { name } } } ... on ProjectV2ItemFieldSingleSelectValue { name field { ... on ProjectV2FieldCommon { name } } } } } content{ __typename ... on DraftIssue { title } ... on Issue { title number } ... on PullRequest { title number } } } } } } }",
                    "variables": { "projectId": "PROJECT_ID", "itemsFirst": 50, "itemsAfter": null, "fieldValuesFirst": 50 }
                  }
                }
              }
            }
          }
        },
        "responses": {
          "200": {
            "description": "GraphQL response (data + optional errors)",
            "content": {
              "application/json": {
                "schema": { "$ref": "#/components/schemas/GraphQLResponse" }
              }
            }
          }
        }
      }
    },
    "/search/issues": {
      "get": {
        "operationId": "searchIssues",
        "summary": "Search issues and pull requests",
        "description": "Search across GitHub issues and pull requests using keywords and qualifiers (e.g. repo:owner/repo, is:issue, label:bug, state:open).",
        "parameters": [
          {
            "name": "q",
            "in": "query",
            "required": true,
            "schema": { "type": "string" },
            "description": "Search query: qualifiers and keywords (e.g. \"repo:owner/repo is:issue label:bug state:open\")."
          },
          {
            "name": "sort",
            "in": "query",
            "required": false,
            "schema": { "type": "string", "enum": ["comments", "created", "updated", "reactions", "interactions", "best-match"] },
            "description": "What to sort results by (e.g. comments count, creation date)."
          },
          {
            "name": "order",
            "in": "query",
            "required": false,
            "schema": { "type": "string", "enum": ["asc", "desc"] },
            "description": "Order of results. Default: desc."
          },
          {
            "name": "per_page",
            "in": "query",
            "required": false,
            "schema": { "type": "integer", "minimum": 1, "maximum": 100 },
            "description": "Results per page (max 100)."
          },
          {
            "name": "page",
            "in": "query",
            "required": false,
            "schema": { "type": "integer", "minimum": 1 },
            "description": "Page number (for pagination)."
          }
        ],
        "responses": {
          "200": {
            "description": "Search results — list of issues or pull requests",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "total_count": { "type": "integer" },
                    "incomplete_results": { "type": "boolean" },
                    "items": {
                      "type": "array",
                      "items": { "$ref": "#/components/schemas/Issue" }
                    }
                  },
                  "required": ["total_count", "items"]
                }
              }
            }
          }
        }
      }
    },
    "/repos/{owner}/{repo}/issues/{issue_number}/comments": {
      "get": {
        "operationId": "getIssueComments",
        "summary": "List comments for a specific issue (or pull request)",
        "description": "Fetches all comments on the specified issue or pull request.",
        "parameters": [
          {
            "name": "owner",
            "in": "path",
            "required": true,
            "schema": { "type": "string" },
            "description": "Owner (user or org) of the repository"
          },
          {
            "name": "repo",
            "in": "path",
            "required": true,
            "schema": { "type": "string" },
            "description": "Repository name"
          },
          {
            "name": "issue_number",
            "in": "path",
            "required": true,
            "schema": { "type": "integer" },
            "description": "Issue (or pull request) number"
          },
          {
            "name": "per_page",
            "in": "query",
            "required": false,
            "schema": { "type": "integer", "minimum": 1, "maximum": 100 },
            "description": "Results per page (max 100)."
          },
          {
            "name": "page",
            "in": "query",
            "required": false,
            "schema": { "type": "integer", "minimum": 1 },
            "description": "Page number (for pagination)."
          }
        ],
        "responses": {
          "200": {
            "description": "List of comments for the issue/PR",
            "content": {
              "application/json": {
                "schema": {
                  "type": "array",
                  "items": { "$ref": "#/components/schemas/IssueComment" }
                }
              }
            }
          }
        }
      }
    },
    "/repos/{owner}/{repo}/issues/comments": {
      "get": {
        "operationId": "getRepoIssueComments",
        "summary": "List all issue/PR comments in a repository",
        "description": "Fetches all comments on issues and pull requests in the specified repository.",
        "parameters": [
          {
            "name": "owner",
            "in": "path",
            "required": true,
            "schema": { "type": "string" }
          },
          {
            "name": "repo",
            "in": "path",
            "required": true,
            "schema": { "type": "string" }
          },
          {
            "name": "per_page",
            "in": "query",
            "required": false,
            "schema": { "type": "integer", "minimum": 1, "maximum": 100 }
          },
          {
            "name": "page",
            "in": "query",
            "required": false,
            "schema": { "type": "integer", "minimum": 1 }
          }
        ],
        "responses": {
          "200": {
            "description": "List of all issue/PR comments in repository",
            "content": {
              "application/json": {
                "schema": {
                  "type": "array",
                  "items": { "$ref": "#/components/schemas/IssueComment" }
                }
              }
            }
          }
        }
      }
    },
    "/repos/{owner}/{repo}/issues/comments/{comment_id}": {
      "get": {
        "operationId": "getSingleIssueComment",
        "summary": "Get a single issue comment by ID",
        "description": "Retrieve a specific comment on any issue or pull request by its ID.",
        "parameters": [
          {
            "name": "owner",
            "in": "path",
            "required": true,
            "schema": { "type": "string" }
          },
          {
            "name": "repo",
            "in": "path",
            "required": true,
            "schema": { "type": "string" }
          },
          {
            "name": "comment_id",
            "in": "path",
            "required": true,
            "schema": { "type": "integer" }
          }
        ],
        "responses": {
          "200": {
            "description": "An issue comment",
            "content": {
              "application/json": {
                "schema": { "$ref": "#/components/schemas/IssueComment" }
              }
            }
          },
          "404": {
            "description": "Comment not found",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": { "message": { "type": "string" } }
                }
              }
            }
          }
        }
      }
    },
    "/repos/{owner}/{repo}/labels": {
      "get": {
        "operationId": "listRepoLabels",
        "summary": "List labels for a repository",
        "description": "List all labels for the specified repository.",
        "parameters": [
          {
            "name": "owner",
            "in": "path",
            "required": true,
            "schema": { "type": "string" },
            "description": "Owner (user or org) of the repository"
          },
          {
            "name": "repo",
            "in": "path",
            "required": true,
            "schema": { "type": "string" },
            "description": "Repository name"
          },
          {
            "name": "per_page",
            "in": "query",
            "required": false,
            "schema": { "type": "integer", "minimum": 1, "maximum": 100 },
            "description": "Results per page (max 100)."
          },
          {
            "name": "page",
            "in": "query",
            "required": false,
            "schema": { "type": "integer", "minimum": 1 },
            "description": "Page number (for pagination)."
          }
        ],
        "responses": {
          "200": {
            "description": "List of labels in the repository",
            "content": {
              "application/json": {
                "schema": {
                  "type": "array",
                  "items": { "$ref": "#/components/schemas/Label" }
                }
              }
            }
          }
        }
      }
    },
    "/repos/{owner}/{repo}/issues/{issue_number}/assignees": {
      "post": {
        "operationId": "addAssignees",
        "summary": "Add assignees to an issue",
        "description": "Adds up to 10 assignees to an issue. Only users with push access can be assigned. Assignees are silently ignored if they don't have push access.",
        "parameters": [
          {
            "name": "owner",
            "in": "path",
            "required": true,
            "schema": { "type": "string" },
            "description": "Owner (user or org) of the repository"
          },
          {
            "name": "repo",
            "in": "path",
            "required": true,
            "schema": { "type": "string" },
            "description": "Repository name"
          },
          {
            "name": "issue_number",
            "in": "path",
            "required": true,
            "schema": { "type": "integer" },
            "description": "Issue number"
          }
        ],
        "requestBody": {
          "required": true,
          "content": {
            "application/json": {
              "schema": { "$ref": "#/components/schemas/AssigneesRequest" }
            }
          }
        },
        "responses": {
          "201": {
            "description": "Issue with updated assignees",
            "content": {
              "application/json": {
                "schema": { "$ref": "#/components/schemas/Issue" }
              }
            }
          }
        }
      },
      "delete": {
        "operationId": "removeAssignees",
        "summary": "Remove assignees from an issue",
        "description": "Removes one or more assignees from an issue.",
        "parameters": [
          {
            "name": "owner",
            "in": "path",
            "required": true,
            "schema": { "type": "string" },
            "description": "Owner (user or org) of the repository"
          },
          {
            "name": "repo",
            "in": "path",
            "required": true,
            "schema": { "type": "string" },
            "description": "Repository name"
          },
          {
            "name": "issue_number",
            "in": "path",
            "required": true,
            "schema": { "type": "integer" },
            "description": "Issue number"
          }
        ],
        "requestBody": {
          "required": true,
          "content": {
            "application/json": {
              "schema": { "$ref": "#/components/schemas/AssigneesRequest" }
            }
          }
        },
        "responses": {
          "200": {
            "description": "Issue with updated assignees",
            "content": {
              "application/json": {
                "schema": { "$ref": "#/components/schemas/Issue" }
              }
            }
          }
        }
      }
    }
  },
  "components": {
    "schemas": {
      "User": {
        "type": "object",
        "properties": {
          "login": { "type": "string" },
          "id": { "type": "integer" },
          "node_id": { "type": "string" },
          "avatar_url": { "type": "string", "format": "uri" },
          "html_url": { "type": "string", "format": "uri" }
        },
        "required": ["login", "id"]
      },
      "Label": {
        "type": "object",
        "properties": {
          "id": { "type": "integer" },
          "node_id": { "type": "string" },
          "url": { "type": "string", "format": "uri" },
          "name": { "type": "string" },
          "color": { "type": "string" },
          "default": { "type": "boolean" },
          "description": { "type": ["string", "null"] }
        },
        "required": ["id", "name", "color"]
      },
      "Issue": {
        "type": "object",
        "properties": {
          "id": { "type": "integer" },
          "number": { "type": "integer" },
          "title": { "type": "string" },
          "state": { "type": "string" },
          "body": { "type": "string" },
          "user": { "$ref": "#/components/schemas/User" },
          "labels": {
            "type": "array",
            "items": { "$ref": "#/components/schemas/Label" }
          },
          "assignees": {
            "type": "array",
            "items": { "$ref": "#/components/schemas/User" }
          },
          "comments": { "type": "integer" },
          "created_at": { "type": "string", "format": "date-time" },
          "updated_at": { "type": "string", "format": "date-time" },
          "pull_request": {
            "type": ["object", "null"],
            "properties": {
              "url": { "type": "string", "format": "uri" },
              "html_url": { "type": "string", "format": "uri" },
              "diff_url": { "type": "string", "format": "uri" },
              "patch_url": { "type": "string", "format": "uri" }
            }
          }
        },
        "required": ["id", "number", "title", "state"]
      },
      "IssueComment": {
        "type": "object",
        "properties": {
          "id": { "type": "integer" },
          "node_id": { "type": "string" },
          "url": { "type": "string", "format": "uri" },
          "html_url": { "type": "string", "format": "uri" },
          "body": { "type": "string" },
          "user": { "$ref": "#/components/schemas/User" },
          "created_at": { "type": "string", "format": "date-time" },
          "updated_at": { "type": "string", "format": "date-time" },
          "issue_url": { "type": "string", "format": "uri" },
          "author_association": { "type": "string" }
        },
        "required": ["id", "url", "body", "user", "created_at", "updated_at"]
      },
      "GraphQLRequest": {
        "type": "object",
        "properties": {
          "query": { "type": "string", "description": "GraphQL query document" },
          "variables": { "type": "object", "additionalProperties": true },
          "operationName": { "type": "string" }
        },
        "required": ["query"]
      },
      "GraphQLError": {
        "type": "object",
        "properties": {
          "message": { "type": "string" },
          "locations": {
            "type": "array",
            "items": {
              "type": "object",
              "properties": {
                "line": { "type": "integer" },
                "column": { "type": "integer" }
              }
            }
          },
          "path": { "type": "array", "items": {} },
          "extensions": { "type": "object", "additionalProperties": true }
        },
        "required": ["message"]
      },
      "GraphQLResponse": {
        "type": "object",
        "properties": {
          "data": { "type": ["object", "null"], "additionalProperties": true },
          "errors": {
            "type": "array",
            "items": { "$ref": "#/components/schemas/GraphQLError" }
          }
        }
      },
      "AssigneesRequest": {
        "type": "object",
        "properties": {
          "assignees": {
            "type": "array",
            "items": { "type": "string" },
            "description": "Usernames of people to assign/unassign. NOTE: Only users with push access can be assigned. Usernames without push access are silently ignored."
          }
        },
        "required": ["assignees"]
      }
    }
  }
}
